    cin >> n >> m;

    auto f=[&](ll a,int v){

        return (a+1)%m;

    };

    auto merge=[&](ll a,ll b){

        return a*b%m;

    };

    ReRooting<ll> re(n,f,merge,1);

    rep(i,n-1){

        int x,y;

        cin >> x >> y;

        x--; y--;

        re.add_E(x,y);

    }

    re.calc();

    rep(i,n){

        cout << re.solve(i) << endl;

    }

    return 0;

}

