void dfs1(int cur,int fa) {

    down[cur] = 1;

    for (int i: e[cur]) if (i!=fa) {

        dfs1(i, cur);

        down[cur] = down[cur] * (down[i]+1) % m;

    }

}

void dfs2(int cur,int fa,LL up) {

    ans[cur] = down[cur] * (up+1) % m;



    int sz = (int)e[cur].size();

    vector<LL> fr, bk;

    fr = vector<LL> (sz);

    bk = vector<LL> (sz);

    REP(i,0,sz-1)               fr[i] = (i>0 ? fr[i-1] : 1LL)    * (e[cur][i]==fa ? (up+1) : (down[e[cur][i]]+1)) % m;

