void add(ll &a, ll b) {

	a = (a + b) % MOD;

	return;

}



void sub(ll &a, ll b) {

	a = (a - b + MOD) % MOD;

	return;

}



void mult(ll &a, ll b) {

	a = 1LL * a * b % MOD;

	return;

}



ll mul(ll a, ll b) {

	return 1LL * a * b % MOD;

}



ll modPow(ll a, ll x) {

	ll res = 1;

	while (x) {

		if (x & 1) mult(res, a);

		mult(a, a);

		x >>= 1;

	}

	return res;

}



ll inv(ll a) {

	return modPow(a, MOD - 2);

}



ll C(ll k, ll n) {

	ll ret = fac[n];

	mult(ret, inv(mul(fac[n - k], fac[k])));

